"use client";

import { useEffect } from "react";
import {
  type AppleLiquidGlassCapture,
  type AppleLiquidGlassEngine,
  type AppleLiquidGlassProfile,
  type AppleLiquidGlassSurface,
  captureAppleLiquidGlassBackdrop,
  createAppleLiquidGlassEngine,
} from "./modern-apple-liquid-glass";

export const appleLiquidGlassSurfaceSelector =
  '[data-control-ui][data-slot][data-surface="floating"], [data-control-ui][data-slot][data-surface="modal"]';
const captureExcludeSelector = '[data-apple-liquid-glass-capture-excluded], [data-control-ui="dynamic-notification"][data-slot="root"]';

type Attachment = AppleLiquidGlassSurface & {
  capture: AppleLiquidGlassCapture | null;
  failures: number;
  geometry: string;
  intersecting: boolean;
  previousStyle: {
    isolation: string;
    position: string;
  };
};

type UnsupportedReason = "unsupported-canvas" | "unsupported-raster" | "unsupported-render" | "unsupported-webgl";

function activeSkin(): boolean {
  return document.documentElement.dataset.skin === "modern-apple";
}

function modernAppleScope(surface: HTMLElement): boolean {
  return surface.closest<HTMLElement>("[data-skin]")?.dataset.skin === "modern-apple";
}

function surfaceProfile(surface: HTMLElement): AppleLiquidGlassProfile {
  return surface.dataset.surface === "modal" ? "modal" : "regular";
}

function createSurfaceCanvas(): HTMLCanvasElement {
  const canvas = document.createElement("canvas");
  canvas.setAttribute("aria-hidden", "true");
  canvas.dataset.extensionNode = "modern-apple-liquid-glass";
  Object.assign(canvas.style, {
    display: "block",
    left: "0",
    opacity: "0",
    pointerEvents: "none",
    position: "absolute",
    top: "0",
    transformOrigin: "top left",
    zIndex: "-1",
  });
  canvas.style.setProperty("border-radius", "inherit");
  canvas.style.setProperty("corner-shape", "inherit");
  return canvas;
}

function primeSurface(surface: HTMLElement): Attachment["previousStyle"] {
  const previousStyle = {
    isolation: surface.style.isolation,
    position: surface.style.position,
  };
  if (getComputedStyle(surface).position === "static") surface.style.position = "relative";
  surface.style.isolation = "isolate";
  return previousStyle;
}

function restoreSurface(surface: HTMLElement, previousStyle: Attachment["previousStyle"]): void {
  surface.style.isolation = previousStyle.isolation;
  surface.style.position = previousStyle.position;
}

function syncCanvasScroll(attachment: Attachment): void {
  attachment.canvas.style.transform = `translate3d(${attachment.host.scrollLeft}px, ${attachment.host.scrollTop}px, 0)`;
}

function clearReadyState(attachment: Attachment): void {
  attachment.canvas.style.opacity = "0";
  delete attachment.host.dataset.appleLiquidGlassReady;
}

function markReady(attachment: Attachment): void {
  attachment.canvas.style.opacity = "1";
  attachment.host.dataset.appleLiquidGlassReady = "true";
}

function geometryKey(host: HTMLElement): string {
  const rect = host.getBoundingClientRect();
  return [rect.left, rect.top, rect.width, rect.height].map((value) => Math.round(value * 4) / 4).join(":");
}

function captureContains(capture: AppleLiquidGlassCapture, attachment: Attachment): boolean {
  const right = capture.region.left + capture.region.width;
  const bottom = capture.region.top + capture.region.height;
  const rect = attachment.host.getBoundingClientRect();
  return rect.left >= capture.region.left && rect.top >= capture.region.top && rect.right <= right && rect.bottom <= bottom;
}

function movedAttachments(attachments: readonly Attachment[]): Attachment[] {
  return attachments.filter((attachment) => {
    const nextGeometry = geometryKey(attachment.host);
    if (nextGeometry === attachment.geometry) return false;
    attachment.geometry = nextGeometry;
    syncCanvasScroll(attachment);
    return true;
  });
}

function renderCachedCapture(engine: AppleLiquidGlassEngine, attachment: Attachment): boolean {
  if (!attachment.capture || !captureContains(attachment.capture, attachment)) return false;
  if (!engine.render(attachment.capture, [attachment])) return false;
  markReady(attachment);
  return true;
}

function surfaceStackLevel(host: HTMLElement): number {
  let level = 0;
  for (let element: HTMLElement | null = host; element; element = element.parentElement) {
    const zIndex = Number.parseInt(getComputedStyle(element).zIndex, 10);
    if (Number.isFinite(zIndex)) level = Math.max(level, zIndex);
  }
  return level;
}

function compareSurfaceStack(a: Attachment, b: Attachment): number {
  const levelDifference = surfaceStackLevel(a.host) - surfaceStackLevel(b.host);
  if (levelDifference !== 0) return levelDifference;
  return a.host.compareDocumentPosition(b.host) & Node.DOCUMENT_POSITION_FOLLOWING ? -1 : 1;
}

export function ModernAppleLiquidGlassRuntime() {
  useEffect(() => {
    const root = document.body;
    const attachments = new Map<HTMLElement, Attachment>();
    let engine: AppleLiquidGlassEngine | null = null;
    let engineUnavailable = false;
    let syncFrame = 0;
    let captureTimer = 0;
    let captureToken = 0;
    let captureRunning = false;
    let captureQueued = false;
    let domObserver: MutationObserver | null = null;
    let disposed = false;
    let geometryFrame = 0;
    let geometryMonitorUntil = 0;

    const scheduleCapture = (delay = 48) => {
      if (disposed) return;
      if (captureRunning) {
        captureQueued = true;
        return;
      }
      window.clearTimeout(captureTimer);
      captureTimer = window.setTimeout(() => {
        captureTimer = 0;
        void recapture();
      }, delay);
    };

    const handleContextState = (available: boolean) => {
      if (!available) {
        for (const attachment of attachments.values()) clearReadyState(attachment);
        return;
      }
      scheduleCapture(0);
    };

    const ensureEngine = (): AppleLiquidGlassEngine | null => {
      if (disposed) return null;
      if (engine) return engine;
      if (engineUnavailable) return null;
      engine = createAppleLiquidGlassEngine(handleContextState);
      if (!engine) engineUnavailable = true;
      return engine;
    };

    const resizeObserver = new ResizeObserver(() => scheduleCapture(80));
    const intersectionObserver = new IntersectionObserver(
      (entries) => {
        for (const entry of entries) {
          if (!(entry.target instanceof HTMLElement)) continue;
          const attachment = attachments.get(entry.target);
          if (attachment) attachment.intersecting = entry.isIntersecting;
        }
        scheduleCapture(80);
      },
      { rootMargin: "96px" },
    );

    const handleSurfaceScroll = (event: Event) => {
      if (!(event.currentTarget instanceof HTMLElement)) return;
      const attachment = attachments.get(event.currentTarget);
      if (attachment) syncCanvasScroll(attachment);
    };

    const attachSurface = (surface: HTMLElement): boolean => {
      if (attachments.has(surface) || surface.dataset.appleLiquidGlass?.startsWith("unsupported")) return false;
      const activeEngine = ensureEngine();
      if (!activeEngine) {
        surface.dataset.appleLiquidGlass = "unsupported-webgl";
        return false;
      }
      const canvas = createSurfaceCanvas();
      if (!canvas.getContext("2d")) {
        surface.dataset.appleLiquidGlass = "unsupported-canvas";
        return false;
      }
      const previousStyle = primeSurface(surface);
      const attachment: Attachment = {
        canvas,
        capture: null,
        failures: 0,
        geometry: geometryKey(surface),
        host: surface,
        intersecting: true,
        previousStyle,
        profile: surfaceProfile(surface),
      };
      surface.dataset.appleLiquidGlass = "active";
      surface.dataset.appleLiquidGlassProfile = attachment.profile;
      surface.prepend(canvas);
      syncCanvasScroll(attachment);
      surface.addEventListener("scroll", handleSurfaceScroll, { passive: true });
      resizeObserver.observe(surface);
      intersectionObserver.observe(surface);
      attachments.set(surface, attachment);
      return true;
    };

    const detachSurface = (surface: HTMLElement, attachment: Attachment, unsupported?: UnsupportedReason): void => {
      resizeObserver.unobserve(surface);
      intersectionObserver.unobserve(surface);
      surface.removeEventListener("scroll", handleSurfaceScroll);
      attachment.canvas.remove();
      restoreSurface(surface, attachment.previousStyle);
      delete surface.dataset.appleLiquidGlassCaptureExcluded;
      delete surface.dataset.appleLiquidGlassReady;
      delete surface.dataset.appleLiquidGlassProfile;
      if (unsupported) surface.dataset.appleLiquidGlass = unsupported;
      else delete surface.dataset.appleLiquidGlass;
    };

    const stopEngine = () => {
      engine?.destroy();
      engine = null;
      engineUnavailable = false;
    };

    const deactivateSurfaces = (): boolean => {
      const changed = attachments.size > 0 || engine !== null;
      captureToken += 1;
      for (const [surface, attachment] of attachments) detachSurface(surface, attachment);
      attachments.clear();
      for (const surface of root.querySelectorAll<HTMLElement>('[data-apple-liquid-glass^="unsupported"]')) {
        delete surface.dataset.appleLiquidGlass;
      }
      stopEngine();
      return changed;
    };

    const attachEligibleSurfaces = (): boolean => {
      let changed = false;
      for (const surface of root.querySelectorAll<HTMLElement>(appleLiquidGlassSurfaceSelector)) {
        if (modernAppleScope(surface)) changed = attachSurface(surface) || changed;
      }
      return changed;
    };

    const detachStaleSurfaces = (): boolean => {
      let changed = false;
      for (const [surface, attachment] of attachments) {
        const stale = !root.contains(surface) || !surface.matches(appleLiquidGlassSurfaceSelector) || !modernAppleScope(surface);
        if (stale) {
          detachSurface(surface, attachment);
          attachments.delete(surface);
          changed = true;
          continue;
        }
        attachment.profile = surfaceProfile(surface);
        surface.dataset.appleLiquidGlassProfile = attachment.profile;
        syncCanvasScroll(attachment);
      }
      return changed;
    };

    const syncSurfaces = (): boolean => {
      if (!activeSkin()) return deactivateSurfaces();
      const attached = attachEligibleSurfaces();
      return detachStaleSurfaces() || attached;
    };

    const visibleAttachments = (): Attachment[] =>
      [...attachments.values()].filter(
        (attachment) =>
          attachment.intersecting && root.contains(attachment.host) && attachment.host.clientWidth > 0 && attachment.host.clientHeight > 0,
      );

    const handleCaptureFailure = (visible: readonly Attachment[], reason: UnsupportedReason) => {
      let retry = false;
      for (const attachment of visible) {
        attachment.failures += 1;
        if (attachment.failures < 3) {
          retry = true;
          continue;
        }
        clearReadyState(attachment);
        detachSurface(attachment.host, attachment, reason);
        attachments.delete(attachment.host);
      }
      if (retry) scheduleCapture(120);
    };

    const handleCaptureSuccess = (visible: readonly Attachment[]) => {
      for (const attachment of visible) {
        attachment.failures = 0;
        markReady(attachment);
      }
    };

    const captureContext = (): { activeEngine: AppleLiquidGlassEngine; visible: Attachment[] } | null => {
      const visible = visibleAttachments();
      if (!activeSkin() || visible.length === 0) return null;
      const activeEngine = ensureEngine();
      return activeEngine && visible.length > 0 ? { activeEngine, visible } : null;
    };

    const finishCapture = (
      activeEngine: AppleLiquidGlassEngine,
      capture: Awaited<ReturnType<typeof captureAppleLiquidGlassBackdrop>>,
      visible: readonly Attachment[],
    ) => {
      if (!capture) {
        handleCaptureFailure(visible, "unsupported-raster");
        return;
      }
      if (activeEngine.render(capture, visible)) {
        for (const attachment of visible) attachment.capture = capture;
        handleCaptureSuccess(visible);
      } else handleCaptureFailure(visible, "unsupported-render");
    };

    const captureAttachment = async (activeEngine: AppleLiquidGlassEngine, attachment: Attachment, token: number) => {
      const capture = await captureAppleLiquidGlassBackdrop([attachment.host], {
        excludeSelector: captureExcludeSelector,
        maxTextureSize: activeEngine.maxTextureSize,
      });
      if (token !== captureToken || !activeSkin()) return false;
      finishCapture(activeEngine, capture, [attachment]);
      delete attachment.host.dataset.appleLiquidGlassCaptureExcluded;
      return true;
    };

    const setCaptureExclusion = (excluded: boolean) => {
      for (const attachment of attachments.values()) {
        if (excluded) attachment.host.dataset.appleLiquidGlassCaptureExcluded = "true";
        else delete attachment.host.dataset.appleLiquidGlassCaptureExcluded;
      }
    };

    const captureStack = async (activeEngine: AppleLiquidGlassEngine, ordered: readonly Attachment[], token: number) => {
      for (const attachment of ordered) {
        if (!(await captureAttachment(activeEngine, attachment, token))) return;
      }
    };

    async function performCapture(): Promise<void> {
      const context = captureContext();
      if (!context) return;

      captureToken += 1;
      const token = captureToken;
      const ordered = [...context.visible].sort(compareSurfaceStack);
      setCaptureExclusion(true);
      await captureStack(context.activeEngine, ordered, token).finally(() => {
        setCaptureExclusion(false);
      });
    }

    async function recapture(): Promise<void> {
      if (disposed) return;
      if (captureRunning) {
        captureQueued = true;
        return;
      }
      captureRunning = true;
      await performCapture().finally(() => {
        captureRunning = false;
        if (captureQueued) {
          captureQueued = false;
          scheduleCapture(80);
        }
      });
    }

    const monitorGeometry = () => {
      geometryFrame = 0;
      if (disposed || !activeSkin() || attachments.size === 0) return;
      const moved = movedAttachments(visibleAttachments());
      const activeEngine = engine;
      const rendered = activeEngine ? moved.map((attachment) => renderCachedCapture(activeEngine, attachment)) : [];
      if (moved.length > 0 && (rendered.length !== moved.length || rendered.includes(false))) scheduleCapture(0);
      if (performance.now() < geometryMonitorUntil) geometryFrame = requestAnimationFrame(monitorGeometry);
    };

    const monitorSurfaceGeometry = (duration = 600) => {
      geometryMonitorUntil = Math.max(geometryMonitorUntil, performance.now() + duration);
      if (geometryFrame === 0 && attachments.size > 0) geometryFrame = requestAnimationFrame(monitorGeometry);
    };

    const handleSurfaceMotion = (event: Event) => {
      if (!(event.target instanceof Element)) return;
      const surface = event.target.closest<HTMLElement>(appleLiquidGlassSurfaceSelector);
      if (surface && attachments.has(surface)) monitorSurfaceGeometry(1200);
    };

    const handleDomMutations = () => {
      scheduleSync();
    };

    const syncDomObserver = () => {
      if (activeSkin() && !domObserver) {
        domObserver = new MutationObserver(handleDomMutations);
        domObserver.observe(root, { childList: true, subtree: true });
        return;
      }
      if (!activeSkin() && domObserver) {
        domObserver.disconnect();
        domObserver = null;
      }
    };

    const performSync = () => {
      syncFrame = 0;
      const changed = syncSurfaces();
      syncDomObserver();
      if (changed && activeSkin()) {
        monitorSurfaceGeometry();
        scheduleCapture(80);
      }
    };

    const scheduleSync = () => {
      if (syncFrame !== 0) return;
      syncFrame = requestAnimationFrame(performSync);
    };

    const handleViewportScroll = (event: Event) => {
      if (event.target instanceof HTMLElement && attachments.has(event.target)) return;
      monitorSurfaceGeometry(240);
      scheduleCapture(32);
    };
    const handleViewportResize = () => scheduleCapture(32);
    const handleLoadedAsset = () => scheduleCapture(0);

    scheduleSync();
    const skinObserver = new MutationObserver(() => {
      scheduleSync();
      scheduleCapture(0);
    });
    skinObserver.observe(document.documentElement, {
      attributes: true,
      attributeFilter: ["class", "data-motion", "data-skin", "style"],
    });
    document.addEventListener("scroll", handleViewportScroll, true);
    root.addEventListener("animationstart", handleSurfaceMotion, true);
    window.addEventListener("resize", handleViewportResize, { passive: true });
    root.addEventListener("load", handleLoadedAsset, true);
    root.addEventListener("transitionrun", handleSurfaceMotion, true);
    void document.fonts?.ready.then(handleLoadedAsset);

    return () => {
      disposed = true;
      captureToken += 1;
      if (syncFrame !== 0) cancelAnimationFrame(syncFrame);
      if (geometryFrame !== 0) cancelAnimationFrame(geometryFrame);
      window.clearTimeout(captureTimer);
      skinObserver.disconnect();
      domObserver?.disconnect();
      resizeObserver.disconnect();
      intersectionObserver.disconnect();
      document.removeEventListener("scroll", handleViewportScroll, true);
      root.removeEventListener("animationstart", handleSurfaceMotion, true);
      window.removeEventListener("resize", handleViewportResize);
      root.removeEventListener("load", handleLoadedAsset, true);
      root.removeEventListener("transitionrun", handleSurfaceMotion, true);
      for (const [surface, attachment] of attachments) detachSurface(surface, attachment);
      attachments.clear();
      stopEngine();
    };
  }, []);

  return null;
}

import { LIQUID_GLASS_OPTICS_GLSL } from "@/components/control-ui/lib/liquid-glass-optics";

export type AppleLiquidGlassProfile = "modal" | "regular";

export type AppleLiquidGlassCapture = {
  frosted: HTMLCanvasElement;
  region: AppleLiquidGlassRegion;
  scale: number;
  sharp: HTMLCanvasElement;
};

export type AppleLiquidGlassRegion = {
  height: number;
  left: number;
  top: number;
  width: number;
};

export type AppleLiquidGlassSurface = {
  canvas: HTMLCanvasElement;
  host: HTMLElement;
  profile: AppleLiquidGlassProfile;
};

export type AppleLiquidGlassEngine = {
  destroy: () => void;
  maxTextureSize: number;
  render: (capture: AppleLiquidGlassCapture, surfaces: readonly AppleLiquidGlassSurface[]) => boolean;
};

type CaptureOptions = {
  excludeSelector: string;
  frost?: number;
  maxTextureSize?: number;
  overscan?: number;
  pixelBudget?: number;
};

type LiquidProgram = {
  appearance: WebGLUniformLocation | null;
  blurTex: WebGLUniformLocation | null;
  blurTexture: WebGLTexture;
  buffer: WebGLBuffer;
  captureOrigin: WebGLUniformLocation | null;
  captureSize: WebGLUniformLocation | null;
  cornerExponent: WebGLUniformLocation | null;
  centerDiffusion: WebGLUniformLocation | null;
  edgeDiffusion: WebGLUniformLocation | null;
  edgeDarkening: WebGLUniformLocation | null;
  edgeHighlight: WebGLUniformLocation | null;
  edgeRatio: WebGLUniformLocation | null;
  fill: WebGLUniformLocation | null;
  fresnel: WebGLUniformLocation | null;
  panelOrigin: WebGLUniformLocation | null;
  program: WebGLProgram;
  radii: WebGLUniformLocation | null;
  refraction: WebGLUniformLocation | null;
  sharpTex: WebGLUniformLocation | null;
  sharpTexture: WebGLTexture;
  size: WebGLUniformLocation | null;
  specular: WebGLUniformLocation | null;
  zRadius: WebGLUniformLocation | null;
};

type MaterialTuning = {
  centerDiffusion: number;
  edgeDiffusion: number;
  edgeDarkening: number;
  edgeHighlight: number;
  edgeRatio: number;
  fill: number;
  fresnel: number;
  refraction: number;
  specular: number;
  zRadius: number;
};

const vertexShader = /* glsl */ `
attribute vec2 a_position;
varying vec2 v_uv;

void main() {
  v_uv = vec2(a_position.x * 0.5 + 0.5, 0.5 - a_position.y * 0.5);
  gl_Position = vec4(a_position, 0.0, 1.0);
}
`;

const fragmentShader = /* glsl */ `
precision highp float;

uniform sampler2D u_sharpTex;
uniform sampler2D u_blurTex;
uniform vec2 u_size;
uniform vec2 u_panelOrigin;
uniform vec2 u_captureOrigin;
uniform vec2 u_captureSize;
uniform vec4 u_radii;
uniform float u_cornerExponent;
uniform float u_zRadius;
uniform float u_edgeRatio;
uniform float u_refraction;
uniform float u_edgeDarkening;
uniform float u_specular;
uniform float u_fresnel;
uniform float u_edgeHighlight;
uniform float u_centerDiffusion;
uniform float u_edgeDiffusion;
uniform float u_fill;
uniform float u_appearance;

varying vec2 v_uv;

${LIQUID_GLASS_OPTICS_GLSL}

float quadrantRadius(vec2 point) {
  if (point.y < 0.0) return point.x < 0.0 ? u_radii.x : u_radii.y;
  return point.x < 0.0 ? u_radii.w : u_radii.z;
}

vec2 captureUV(vec2 viewportPosition) {
  return clamp((viewportPosition - u_captureOrigin) / u_captureSize, 0.0, 1.0);
}

void main() {
  vec2 local = (v_uv - 0.5) * u_size;
  vec2 halfSize = u_size * 0.5;
  float radius = min(quadrantRadius(local), min(halfSize.x, halfSize.y));
  float sdf = liquidSurfaceSDF(local, halfSize, radius, u_cornerExponent);
  float mask = 1.0 - smoothstep(-1.5, 0.5, sdf);

  if (mask <= 0.0) {
    gl_FragColor = vec4(0.0);
    return;
  }

  float edgeWidth = liquidEdgeWidth(u_size, u_edgeRatio, u_zRadius);
  float opticalInside = liquidOpticalInsideDistance(local, halfSize, radius, u_cornerExponent);
  float lens = liquidEdgeLens(opticalInside, edgeWidth);
  vec2 boundaryNormal = liquidInwardOpticalNormal(local, halfSize, radius, u_cornerExponent);
  vec2 refractedOffset = liquidRefractedOffset(boundaryNormal, opticalInside, edgeWidth, u_refraction);
  vec2 samplePosition = u_panelOrigin + v_uv * u_size + refractedOffset;
  vec3 sharp = texture2D(u_sharpTex, captureUV(samplePosition)).rgb;
  vec3 frosted = texture2D(u_blurTex, captureUV(samplePosition)).rgb;
  vec3 color = mix(sharp, frosted, mix(u_centerDiffusion, u_edgeDiffusion, lens));

  float transmittedLuma = dot(color, vec3(0.2126, 0.7152, 0.0722));
  float blackEndpoint = mix(0.20, 0.05, u_appearance);
  float whiteEndpoint = mix(0.95, 0.80, u_appearance);
  float mappedLuma = mix(blackEndpoint, whiteEndpoint, transmittedLuma);
  color = clamp(color + vec3(mappedLuma - transmittedLuma), 0.0, 1.0);
  vec3 materialTint = mix(vec3(1.0), vec3(0.035), u_appearance);
  color = mix(color, materialTint, mix(u_fill, u_fill * 0.38, lens));

  vec2 keyDirection = normalize(vec2(0.707106, -0.707106));
  float outerRim = 1.0 - smoothstep(0.35, 1.35, opticalInside);
  float innerRim = exp(-pow((opticalInside - 2.0) / 0.9, 2.0));
  float keyArc = pow(max(dot(boundaryNormal, keyDirection), 0.0), 6.0);
  float fillArc = pow(max(dot(boundaryNormal, -keyDirection), 0.0), 8.0) * 0.28;
  float shadowArc = pow(max(dot(boundaryNormal, -keyDirection), 0.0), 6.0);
  color *= 1.0 - innerRim * shadowArc * u_edgeDarkening;
  float highlight = outerRim * u_edgeHighlight * 0.22 + innerRim * (keyArc * u_specular + fillArc * u_specular * 1.3);
  float grazing = outerRim * u_fresnel * 0.025;
  vec3 rimLight = mix(vec3(1.0), frosted, 0.12);
  vec3 material = color + rimLight * highlight + vec3(grazing);

  gl_FragColor = vec4(material * mask, mask);
}
`;

function numberToken(styles: CSSStyleDeclaration, name: string, fallback: number): number {
  const value = Number.parseFloat(styles.getPropertyValue(name));
  return Number.isFinite(value) ? value : fallback;
}

function materialTuning(host: HTMLElement, profile: AppleLiquidGlassProfile): MaterialTuning {
  const styles = getComputedStyle(host);
  const modal = profile === "modal";
  return {
    refraction: numberToken(styles, modal ? "--apple-liquid-modal-refraction" : "--apple-liquid-refraction", modal ? 0.92 : 0.85),
    zRadius: numberToken(styles, "--apple-liquid-edge-band", 32),
    edgeRatio: numberToken(styles, modal ? "--apple-liquid-modal-edge-ratio" : "--apple-liquid-edge-ratio", modal ? 0.25 : 0.36),
    edgeDarkening: numberToken(styles, "--apple-liquid-edge-darkening", 0.025),
    specular: numberToken(styles, "--apple-liquid-specular", 0.11),
    fresnel: numberToken(styles, "--apple-liquid-fresnel", 0.35),
    edgeHighlight: numberToken(styles, "--apple-liquid-edge-highlight", 0.16),
    centerDiffusion: numberToken(
      styles,
      modal ? "--apple-liquid-modal-center-diffusion" : "--apple-liquid-center-diffusion",
      modal ? 0.82 : 0.38,
    ),
    edgeDiffusion: numberToken(
      styles,
      modal ? "--apple-liquid-modal-edge-diffusion" : "--apple-liquid-edge-diffusion",
      modal ? 0.32 : 0.08,
    ),
    fill: numberToken(styles, modal ? "--apple-liquid-modal-fill" : "--apple-liquid-fill", modal ? 0.6 : 0.32),
  };
}

function compileShader(gl: WebGLRenderingContext, type: number, source: string): WebGLShader | null {
  const shader = gl.createShader(type);
  if (!shader) return null;
  gl.shaderSource(shader, source);
  gl.compileShader(shader);
  if (gl.getShaderParameter(shader, gl.COMPILE_STATUS)) return shader;
  gl.deleteShader(shader);
  return null;
}

function createTexture(gl: WebGLRenderingContext): WebGLTexture | null {
  const texture = gl.createTexture();
  if (!texture) return null;
  gl.bindTexture(gl.TEXTURE_2D, texture);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
  return texture;
}

function buildProgram(gl: WebGLRenderingContext): LiquidProgram | null {
  const vertex = compileShader(gl, gl.VERTEX_SHADER, vertexShader);
  const fragment = compileShader(gl, gl.FRAGMENT_SHADER, fragmentShader);
  if (!vertex || !fragment) return null;
  const program = gl.createProgram();
  const buffer = gl.createBuffer();
  const sharpTexture = createTexture(gl);
  const blurTexture = createTexture(gl);
  if (!program || !buffer || !sharpTexture || !blurTexture) return null;

  gl.attachShader(program, vertex);
  gl.attachShader(program, fragment);
  gl.linkProgram(program);
  gl.deleteShader(vertex);
  gl.deleteShader(fragment);
  if (!gl.getProgramParameter(program, gl.LINK_STATUS)) return null;

  gl.bindBuffer(gl.ARRAY_BUFFER, buffer);
  gl.bufferData(gl.ARRAY_BUFFER, new Float32Array([-1, -1, 1, -1, -1, 1, 1, 1]), gl.STATIC_DRAW);
  const position = gl.getAttribLocation(program, "a_position");
  gl.enableVertexAttribArray(position);
  gl.vertexAttribPointer(position, 2, gl.FLOAT, false, 0, 0);

  return {
    program,
    buffer,
    sharpTexture,
    blurTexture,
    sharpTex: gl.getUniformLocation(program, "u_sharpTex"),
    blurTex: gl.getUniformLocation(program, "u_blurTex"),
    size: gl.getUniformLocation(program, "u_size"),
    panelOrigin: gl.getUniformLocation(program, "u_panelOrigin"),
    captureOrigin: gl.getUniformLocation(program, "u_captureOrigin"),
    captureSize: gl.getUniformLocation(program, "u_captureSize"),
    radii: gl.getUniformLocation(program, "u_radii"),
    cornerExponent: gl.getUniformLocation(program, "u_cornerExponent"),
    zRadius: gl.getUniformLocation(program, "u_zRadius"),
    edgeRatio: gl.getUniformLocation(program, "u_edgeRatio"),
    refraction: gl.getUniformLocation(program, "u_refraction"),
    edgeDarkening: gl.getUniformLocation(program, "u_edgeDarkening"),
    specular: gl.getUniformLocation(program, "u_specular"),
    fresnel: gl.getUniformLocation(program, "u_fresnel"),
    edgeHighlight: gl.getUniformLocation(program, "u_edgeHighlight"),
    centerDiffusion: gl.getUniformLocation(program, "u_centerDiffusion"),
    edgeDiffusion: gl.getUniformLocation(program, "u_edgeDiffusion"),
    fill: gl.getUniformLocation(program, "u_fill"),
    appearance: gl.getUniformLocation(program, "u_appearance"),
  };
}

function radius(
  styles: CSSStyleDeclaration,
  property: "borderTopLeftRadius" | "borderTopRightRadius" | "borderBottomRightRadius" | "borderBottomLeftRadius",
  host: HTMLElement,
): number {
  const value = Number.parseFloat(styles[property]);
  return Number.isFinite(value) ? Math.min(Math.max(value, 0), Math.min(host.clientWidth, host.clientHeight) / 2) : 0;
}

function cornerExponent(styles: CSSStyleDeclaration): number {
  if (!CSS.supports("corner-shape: squircle")) return 2;
  const shape = [
    styles.getPropertyValue("corner-shape"),
    styles.getPropertyValue("--corner-shape-popover"),
    styles.getPropertyValue("--corner-shape-panel"),
    styles.getPropertyValue("--corner-shape"),
  ]
    .join(" ")
    .toLowerCase();
  return shape.includes("squircle") || shape.includes("superellipse") ? 4 : 2;
}

function darkAppearance(host: HTMLElement): number {
  return host.closest(".dark") || document.documentElement.classList.contains("dark") ? 1 : 0;
}

function uploadCapture(gl: WebGLRenderingContext, liquid: LiquidProgram, capture: AppleLiquidGlassCapture): boolean {
  try {
    for (let index = 0; index < 8 && gl.getError() !== gl.NO_ERROR; index += 1) {
      // Drain stale errors so the checks below describe these uploads.
    }
    gl.pixelStorei(gl.UNPACK_PREMULTIPLY_ALPHA_WEBGL, true);
    gl.activeTexture(gl.TEXTURE0);
    gl.bindTexture(gl.TEXTURE_2D, liquid.sharpTexture);
    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, capture.sharp);
    if (gl.getError() !== gl.NO_ERROR) return false;
    gl.activeTexture(gl.TEXTURE1);
    gl.bindTexture(gl.TEXTURE_2D, liquid.blurTexture);
    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, capture.frosted);
    return gl.getError() === gl.NO_ERROR;
  } catch {
    return false;
  }
}

function setCaptureUniforms(gl: WebGLRenderingContext, liquid: LiquidProgram, capture: AppleLiquidGlassCapture): void {
  // biome-ignore lint/correctness/useHookAtTopLevel: WebGL's useProgram is not a React hook.
  gl.useProgram(liquid.program);
  gl.uniform1i(liquid.sharpTex, 0);
  gl.uniform1i(liquid.blurTex, 1);
  gl.uniform2f(liquid.captureOrigin, capture.region.left, capture.region.top);
  gl.uniform2f(liquid.captureSize, capture.region.width, capture.region.height);
}

function setSurfaceUniforms(
  gl: WebGLRenderingContext,
  liquid: LiquidProgram,
  host: HTMLElement,
  profile: AppleLiquidGlassProfile,
  cssWidth: number,
  cssHeight: number,
): void {
  const hostRect = host.getBoundingClientRect();
  const styles = getComputedStyle(host);
  const tuning = materialTuning(host, profile);
  gl.uniform2f(liquid.size, cssWidth, cssHeight);
  gl.uniform2f(liquid.panelOrigin, hostRect.left, hostRect.top);
  gl.uniform4f(
    liquid.radii,
    radius(styles, "borderTopLeftRadius", host),
    radius(styles, "borderTopRightRadius", host),
    radius(styles, "borderBottomRightRadius", host),
    radius(styles, "borderBottomLeftRadius", host),
  );
  gl.uniform1f(liquid.cornerExponent, cornerExponent(styles));
  gl.uniform1f(liquid.zRadius, tuning.zRadius);
  gl.uniform1f(liquid.edgeRatio, tuning.edgeRatio);
  gl.uniform1f(liquid.refraction, tuning.refraction);
  gl.uniform1f(liquid.edgeDarkening, tuning.edgeDarkening);
  gl.uniform1f(liquid.specular, tuning.specular);
  gl.uniform1f(liquid.fresnel, tuning.fresnel);
  gl.uniform1f(liquid.edgeHighlight, tuning.edgeHighlight);
  gl.uniform1f(liquid.centerDiffusion, tuning.centerDiffusion);
  gl.uniform1f(liquid.edgeDiffusion, tuning.edgeDiffusion);
  gl.uniform1f(liquid.fill, tuning.fill);
  gl.uniform1f(liquid.appearance, darkAppearance(host));
}

function renderSurface(
  gl: WebGLRenderingContext,
  scratch: HTMLCanvasElement,
  liquid: LiquidProgram,
  { canvas, host, profile }: AppleLiquidGlassSurface,
): boolean {
  const context = canvas.getContext("2d");
  if (!context) return false;
  const cssWidth = Math.max(1, host.clientWidth);
  const cssHeight = Math.max(1, host.clientHeight);
  const dpr = Math.min(window.devicePixelRatio || 1, 2);
  const width = Math.max(1, Math.round(cssWidth * dpr));
  const height = Math.max(1, Math.round(cssHeight * dpr));
  if (scratch.width !== width) scratch.width = width;
  if (scratch.height !== height) scratch.height = height;
  gl.viewport(0, 0, width, height);
  gl.clearColor(0, 0, 0, 0);
  gl.clear(gl.COLOR_BUFFER_BIT);
  // biome-ignore lint/correctness/useHookAtTopLevel: WebGL's useProgram is not a React hook.
  gl.useProgram(liquid.program);
  setSurfaceUniforms(gl, liquid, host, profile, cssWidth, cssHeight);
  gl.drawArrays(gl.TRIANGLE_STRIP, 0, 4);
  gl.flush();
  if (gl.getError() !== gl.NO_ERROR) return false;

  if (canvas.width !== width) canvas.width = width;
  if (canvas.height !== height) canvas.height = height;
  canvas.style.width = `${cssWidth}px`;
  canvas.style.height = `${cssHeight}px`;
  context.clearRect(0, 0, width, height);
  context.drawImage(scratch, 0, 0, width, height);
  return true;
}

function renderCapture(
  gl: WebGLRenderingContext,
  scratch: HTMLCanvasElement,
  liquid: LiquidProgram,
  capture: AppleLiquidGlassCapture,
  surfaces: readonly AppleLiquidGlassSurface[],
  upload: boolean,
): boolean {
  if (upload && !uploadCapture(gl, liquid, capture)) return false;
  setCaptureUniforms(gl, liquid, capture);
  if (surfaces.length === 0) return false;
  return surfaces.every((surface) => renderSurface(gl, scratch, liquid, surface));
}

export function createAppleLiquidGlassEngine(onContextStateChange?: (available: boolean) => void): AppleLiquidGlassEngine | null {
  const scratch = document.createElement("canvas");
  const gl = scratch.getContext("webgl", { alpha: true, antialias: true, premultipliedAlpha: true });
  if (!gl) return null;
  let liquid = buildProgram(gl);
  if (!liquid) return null;
  let destroyed = false;
  let contextLost = false;
  let uploadedCapture: AppleLiquidGlassCapture | null = null;

  const handleContextLost = (event: Event) => {
    event.preventDefault();
    contextLost = true;
    uploadedCapture = null;
    onContextStateChange?.(false);
  };
  const handleContextRestored = () => {
    contextLost = false;
    liquid = buildProgram(gl);
    uploadedCapture = null;
    onContextStateChange?.(liquid !== null);
  };
  scratch.addEventListener("webglcontextlost", handleContextLost);
  scratch.addEventListener("webglcontextrestored", handleContextRestored);

  // getParameter is typed any and returns null on a lost context; fall back to the capture default.
  const maxTextureSize: unknown = gl.getParameter(gl.MAX_TEXTURE_SIZE);

  return {
    maxTextureSize: typeof maxTextureSize === "number" ? maxTextureSize : 4096,
    render(capture, surfaces) {
      if (destroyed || contextLost || !liquid) return false;
      const upload = uploadedCapture !== capture;
      const rendered = renderCapture(gl, scratch, liquid, capture, surfaces, upload);
      if (rendered && upload) uploadedCapture = capture;
      return rendered;
    },
    destroy() {
      destroyed = true;
      scratch.removeEventListener("webglcontextlost", handleContextLost);
      scratch.removeEventListener("webglcontextrestored", handleContextRestored);
      if (liquid && !gl.isContextLost()) {
        gl.deleteProgram(liquid.program);
        gl.deleteBuffer(liquid.buffer);
        gl.deleteTexture(liquid.sharpTexture);
        gl.deleteTexture(liquid.blurTexture);
      }
      liquid = null;
      uploadedCapture = null;
    },
  };
}

