function cloneCanvas(source: HTMLCanvasElement): HTMLImageElement | null {
  try {
    const image = document.createElement("img");
    image.src = source.toDataURL();
    image.setAttribute("style", computedCssText(source));
    return image;
  } catch {
    return null;
  }
}

function syncLiveValue(source: Element, clone: Element): void {
  if (source instanceof HTMLInputElement && clone instanceof HTMLInputElement) clone.value = source.value;
  if (source instanceof HTMLTextAreaElement && clone instanceof HTMLTextAreaElement) clone.value = source.value;
  if (source instanceof HTMLImageElement && clone instanceof HTMLImageElement && source.currentSrc) clone.src = source.currentSrc;
}

function appendClonedChildren(source: Element, clone: Element, excludeSelector: string, region: AppleLiquidGlassRegion): void {
  for (const child of source.childNodes) {
    if (child instanceof Element) {
      const childClone = cloneTree(child, excludeSelector, region);
      if (childClone) clone.appendChild(childClone);
      continue;
    }
    if (child.nodeType === Node.TEXT_NODE) clone.appendChild(child.cloneNode(false));
  }
}

function intersectsRegion(source: Element, region: AppleLiquidGlassRegion): boolean {
  if (source === document.body) return true;
  const rect = source.getBoundingClientRect();
  if (getComputedStyle(source).display === "contents") return true;
  return (
    rect.right > region.left && rect.bottom > region.top && rect.left < region.left + region.width && rect.top < region.top + region.height
  );
}

function clonePlaceholder(source: Element): Element | null {
  const clone = source.cloneNode(false);
  if (!(clone instanceof Element)) return null;
  clone.setAttribute("style", computedCssText(source));
  if (!(clone instanceof HTMLElement)) return clone;
  const rect = source.getBoundingClientRect();
  Object.assign(clone.style, {
    height: `${Math.max(0, rect.height)}px`,
    minHeight: "0",
    minWidth: "0",
    overflow: "hidden",
    visibility: "hidden",
    width: `${Math.max(0, rect.width)}px`,
  });
  return clone;
}

function cloneTree(source: Element, excludeSelector: string, region: AppleLiquidGlassRegion): Element | null {
  if (source.matches(excludeSelector)) return null;
  if (!intersectsRegion(source, region)) return clonePlaceholder(source);
  if (source instanceof HTMLCanvasElement) return cloneCanvas(source);
  const clone = source.cloneNode(false);
  if (!(clone instanceof Element)) return null;
  clone.setAttribute("style", computedCssText(source));
  syncLiveValue(source, clone);
  appendClonedChildren(source, clone, excludeSelector, region);
  return clone;
}

function computedCssText(source: Element): string {
  const computed = getComputedStyle(source);
  const declarations = capturedStyleProperties.map((property) => `${property}: ${computed.getPropertyValue(property)};`);
  declarations.push("animation: none !important; transition: none !important; caret-color: transparent !important;");
  return declarations.join(" ");
}

function regionForHosts(hosts: readonly HTMLElement[], overscan: number): AppleLiquidGlassRegion | null {
  const rects = hosts.flatMap((host) => {
    const rect = host.getBoundingClientRect();
    const visible =
      rect.width > 0 &&
      rect.height > 0 &&
      rect.right > 0 &&
      rect.bottom > 0 &&
      rect.left < window.innerWidth &&
      rect.top < window.innerHeight;
    return visible ? [rect] : [];
  });
  if (rects.length === 0) return null;
  const left = Math.max(0, Math.floor(Math.min(...rects.map((rect) => rect.left)) - overscan));
  const top = Math.max(0, Math.floor(Math.min(...rects.map((rect) => rect.top)) - overscan));
  const right = Math.min(window.innerWidth, Math.ceil(Math.max(...rects.map((rect) => rect.right)) + overscan));
  const bottom = Math.min(window.innerHeight, Math.ceil(Math.max(...rects.map((rect) => rect.bottom)) + overscan));
  return { left, top, width: Math.max(1, right - left), height: Math.max(1, bottom - top) };
}

function scaleCanvas(source: HTMLCanvasElement, width: number, height: number): HTMLCanvasElement | null {
  const canvas = document.createElement("canvas");
  canvas.width = width;
  canvas.height = height;
  const context = canvas.getContext("2d");
  if (!context) return null;
  context.imageSmoothingEnabled = true;
  context.imageSmoothingQuality = "high";
  context.drawImage(source, 0, 0, width, height);
  return canvas;
}

function frostCanvas(sharp: HTMLCanvasElement, frost: number): HTMLCanvasElement | null {
  const frosted = document.createElement("canvas");
  frosted.width = sharp.width;
  frosted.height = sharp.height;
  const context = frosted.getContext("2d");
  if (!context) return null;
  if (frost <= 1) {
    context.drawImage(sharp, 0, 0);
    return frosted;
  }

  const targetWidth = Math.max(1, Math.round(sharp.width / frost));
  const targetHeight = Math.max(1, Math.round(sharp.height / frost));
  let reduced: HTMLCanvasElement | null = sharp;
  let width = sharp.width;
  let height = sharp.height;
  while (reduced && width * 0.5 >= targetWidth) {
    width = Math.max(targetWidth, Math.round(width * 0.5));
    height = Math.max(targetHeight, Math.round(height * 0.5));
    reduced = scaleCanvas(reduced, width, height);
  }
  if (reduced && (reduced.width !== targetWidth || reduced.height !== targetHeight))
    reduced = scaleCanvas(reduced, targetWidth, targetHeight);
  const bounced = reduced
    ? scaleCanvas(reduced, Math.max(1, Math.round(targetWidth / 2)), Math.max(1, Math.round(targetHeight / 2)))
    : null;
  const smoothed = bounced ? (scaleCanvas(bounced, targetWidth, targetHeight) ?? reduced) : reduced;
  context.imageSmoothingEnabled = true;
  context.imageSmoothingQuality = "high";
  context.drawImage(smoothed ?? sharp, 0, 0, frosted.width, frosted.height);
  return frosted;
}

function captureScale(region: AppleLiquidGlassRegion, maxTextureSize: number, pixelBudget: number): number {
  const desired = Math.min((window.devicePixelRatio || 1) * 1.25, 2.5);
  const dimensionLimit = maxTextureSize / Math.max(region.width, region.height, 1);
  const pixelLimit = Math.sqrt(pixelBudget / Math.max(region.width * region.height, 1));
  return Math.min(desired, dimensionLimit, pixelLimit);
}

function decodeImage(image: HTMLImageElement): Promise<void> {
  if (typeof image.decode === "function") return image.decode();
  return new Promise((resolve, reject) => {
    image.onload = () => resolve();
    image.onerror = () => reject(new Error("Unable to decode liquid glass capture"));
  });
}

async function decodeSvg(svg: string): Promise<CanvasImageSource | null> {
  if (typeof createImageBitmap === "function") {
    try {
      return await createImageBitmap(new Blob([svg], { type: "image/svg+xml;charset=utf-8" }));
    } catch {
      // Older WebKit builds need the image decoder path.
    }
  }
  const image = new Image();
  image.decoding = "async";
  image.src = `data:image/svg+xml;charset=utf-8,${encodeURIComponent(svg)}`;
  try {
    await decodeImage(image);
    return image;
  } catch {
    return null;
  }
}

export async function captureAppleLiquidGlassBackdrop(
  hosts: readonly HTMLElement[],
  { excludeSelector, frost = 10, maxTextureSize = 4096, overscan = 64, pixelBudget = 6_000_000 }: CaptureOptions,
): Promise<AppleLiquidGlassCapture | null> {
  const region = regionForHosts(hosts, overscan);
  if (!region) return null;
  const bodyClone = cloneTree(document.body, excludeSelector, region);
  if (!(bodyClone instanceof HTMLElement)) return null;
  const bodyRect = document.body.getBoundingClientRect();

  const stage = document.createElement("div");
  const rootStyles = getComputedStyle(document.documentElement);
  stage.setAttribute("xmlns", "http://www.w3.org/1999/xhtml");
  Object.assign(stage.style, {
    backgroundColor: rootStyles.backgroundColor,
    backgroundImage: rootStyles.backgroundImage,
    backgroundPosition: rootStyles.backgroundPosition,
    backgroundRepeat: rootStyles.backgroundRepeat,
    backgroundSize: rootStyles.backgroundSize,
    height: `${region.height}px`,
    overflow: "hidden",
    position: "relative",
    width: `${region.width}px`,
  });
  Object.assign(bodyClone.style, {
    height: "auto",
    left: `${bodyRect.left - region.left}px`,
    margin: "0",
    minHeight: `${Math.max(document.documentElement.scrollHeight, window.innerHeight)}px`,
    position: "absolute",
    top: `${bodyRect.top - region.top}px`,
    width: `${bodyRect.width}px`,
  });
  stage.appendChild(bodyClone);

  const scale = captureScale(region, maxTextureSize, pixelBudget);
  const width = Math.max(1, Math.round(region.width * scale));
  const height = Math.max(1, Math.round(region.height * scale));
  const markup = new XMLSerializer().serializeToString(stage);
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${region.width} ${region.height}"><foreignObject width="${region.width}" height="${region.height}">${markup}</foreignObject></svg>`;
  const image = await decodeSvg(svg);
  if (!image) return null;

  const sharp = document.createElement("canvas");
  sharp.width = width;
  sharp.height = height;
  const context = sharp.getContext("2d");
  if (!context) {
    if (typeof ImageBitmap !== "undefined" && image instanceof ImageBitmap) image.close();
    return null;
  }
  try {
    context.drawImage(image, 0, 0, width, height);
  } catch {
    return null;
  } finally {
    if (typeof ImageBitmap !== "undefined" && image instanceof ImageBitmap) image.close();
  }
  const frosted = frostCanvas(sharp, frost);
  return frosted ? { sharp, frosted, region, scale } : null;
}

import type { ControlUiSkin } from "@/components/control-ui/skin";

/*
 * ADVANCED skin: mount ModernAppleLiquidGlassRuntime once for WebGL floating surfaces; skin.css
 * keeps the unsupported-browser fallback while these slots style controls and content.
 */

// white focus halo — the ring token is white in this skin, so focus reads as a soft luminous glow.
const appleFocus = "focus-visible:ring-[3px] focus-visible:ring-[var(--ring)] focus-visible:ring-offset-0";

// Glass wafer: translucent white control, backdrop-blur, 0.5px ring (not base's ring-1) —
// tailwind-merge keeps last ring since skin classes append after base. Shadow overrides base via
// arg-order (leading `inset_` reads as box-shadow); ambiguous bare `shadow-[var(--x)]` needs `shadow-(--x)`.
const appleGlass =
  "bg-[var(--glass-fill)] text-foreground backdrop-blur-[var(--backdrop-blur-glass)] backdrop-saturate-[1.8] ring-[0.5px] ring-inset ring-[var(--glass-rim)] shadow-[inset_0_1px_0_0_var(--glass-gloss),0_1px_2px_0_rgba(0,0,0,0.06)] hover:bg-[var(--glass-fill-hover)] active:bg-[var(--glass-fill-active)] active:scale-[0.97]";
const appleControl = `rounded-[var(--radius-control)] ${appleGlass} ${appleFocus}`;

// the solid variant = the system-blue capsule CTA, with its own white top gloss so it reads as glass.
const appleSolid = `rounded-[var(--radius-control)] border-0 bg-[var(--primary)] text-[var(--primary-foreground)] shadow-[inset_0_1px_0_0_rgba(255,255,255,0.35),0_1px_3px_0_rgba(10,102,240,0.4)] hover:brightness-105 active:brightness-95 active:scale-[0.97] ${appleFocus}`;

// Transparent glass field: frosted backdrop + white rim, no solid fill ("input transparent" ask).
const appleField = `rounded-[var(--radius-control)] border border-[var(--input)] bg-transparent text-foreground backdrop-blur-[var(--backdrop-blur-glass)] backdrop-saturate-[1.8] shadow-[inset_0_1px_2px_rgba(0,0,0,0.04)] ${appleFocus}`;

// Floating popup: geometry only (radius+row padding) — full DS material painted in skin.css globally.
const applePopup = "rounded-[0.75rem] p-1";
// Menu row: 24px (DS Menu/Height=1.5rem), 13px text. Active row = solid #0069f9 pill w/ WHITE
// text (DS node 2004:25249), not translucent tint. `group/mi` whitens row's icons+shortcut too.
const appleItem =
  "group/mi min-h-[1.5rem] rounded-[var(--radius-popup-item)] px-2 py-0.5 text-[13px] data-[highlighted]:bg-[var(--menu-selection)] data-[highlighted]:text-white data-[disabled]:opacity-40";
const appleMenuLabel = "px-2 py-1 text-label font-semibold normal-case tracking-normal text-muted-foreground";
const appleSeparator = "mx-0 my-1 bg-[var(--hairline)]";

export const skin: ControlUiSkin = {
  id: "modern-apple",
  // Apple floats sidebar (native shadcn `floating` variant, detached rounded panel) while content
  // stays flat; component reads via skinSidebarLayout(), skin.css re-materialises panel as glass.
  sidebarLayout: "floating",
  slots: {
    button: {
      root: ({ variant }) => (variant === "solid" ? appleSolid : appleControl),
    },
    menu: {
      trigger: appleControl,
      content: applePopup,
      item: appleItem,
      separator: appleSeparator,
      label: appleMenuLabel,
    },
    "context-menu": {
      content: applePopup,
      "sub-content": applePopup,
      item: appleItem,
      "checkbox-item": appleItem,
      "radio-item": appleItem,
      "sub-trigger": `${appleItem} data-[popup-open]:bg-[var(--menu-selection)] data-[popup-open]:text-white`,
      separator: appleSeparator,
      label: appleMenuLabel,
      shortcut: "ml-auto text-meta tracking-widest text-muted-foreground group-data-[highlighted]/cmi:text-white",
    },
    select: {
      trigger: appleControl,
      content: applePopup,
      item: `${appleItem} data-[highlighted]:[&>span:last-child]:text-white`,
    },
    "thread-rail": {
      popover: "rounded-[var(--radius-lg)]",
    },
    activity: {
      root: ({ kind }) =>
        kind === "tool"
          ? "rounded-[var(--radius-panel)] border border-[var(--glass-rim)] bg-[var(--glass-fill)] backdrop-blur-[var(--backdrop-blur-glass)] backdrop-saturate-[1.8]"
          : undefined,
      trigger: ({ kind }) => (kind === "tool" ? "bg-transparent" : undefined),
    },
    input: {
      root: appleField,
    },
    "input-group": {
      root: appleField,
    },
    dialog: {
      content: "rounded-[0.75rem]",
      title: "text-[15px] font-semibold",
      description: "text-body text-muted-foreground",
    },
    "sidebar-layout": {
      content: "m-0 rounded-none border-0 bg-transparent shadow-none lg:m-0",
    },
    sidebar: {
      inner:
        "rounded-[var(--radius-panel)] border border-[var(--glass-rim)] bg-[var(--glass-fill)] backdrop-blur-[var(--backdrop-blur-glass)] backdrop-saturate-[1.8]",
      "menu-button":
        "rounded-[var(--radius-control)] data-[active=true]:bg-[oklch(from_var(--primary)_l_c_h/0.14)] data-[active=true]:text-foreground",
    },
    slider: {
      thumb: "rounded-full border border-[var(--glass-rim)] bg-white shadow-[0_1px_3px_rgba(0,0,0,0.28)]",
      indicator: "bg-[var(--primary)]",
    },
    "chat-message": {
      content:
        "data-[role=user]:rounded-[var(--radius-field)] data-[role=user]:bg-[var(--primary)] data-[role=user]:text-[var(--primary-foreground)] data-[role=user]:shadow-none",
    },
    "chat-input": {
      shell: `rounded-[var(--radius-field)] ${appleField}`,
      submit: appleSolid,
    },
    "markdown-block": {
      root: "rounded-[var(--radius-panel)] border border-[var(--glass-rim)]",
    },
    "chat-scene": {
      root: "rounded-[var(--radius-scene)] border border-[var(--glass-rim)] bg-[oklch(from_var(--card)_l_c_h/0.7)] backdrop-blur-[var(--backdrop-blur-popover)] backdrop-saturate-[1.8] shadow-(--shadow-soft)",
    },
  },
};

/*
 * Pack's own vars + glass utilities. Import after Tailwind+theme. The root runtime progressively
 * replaces the CSS fallback with refractive WebGL while segmented-tab knobs remain CSS-only, all under
 * [data-skin="modern-apple"] so multiple skins co-compile in one build (no @utility — global).
 */

/* Pack's own vars (glass tints, edge-highlight, hairlines, segmented control) — NOT in theme.css
 * token contract. Mode-dependent, same light/dark scoping as theme.css; unlayered so consumers inherit. */
[data-skin="modern-apple"] {
  --hairline: oklch(0 0 0 / 0.06);
  /* the Liquid-Glass control fill — a translucent white wafer the backdrop shows through */
  --glass-fill: oklch(1 0 0 / 0.55);
  --glass-fill-hover: oklch(1 0 0 / 0.7);
  --glass-fill-active: oklch(1 0 0 / 0.42);
  /* the bright white rim + top gloss that gives the glass its edge ("ring white") */
  --glass-rim: oklch(1 0 0 / 0.55);
  --glass-gloss: oklch(1 0 0 / 0.75);
  --backdrop-blur-glass: 10px; /* DS Liquid Glass/Frost — Regular = 6 (controls frost lighter than large surfaces); 10px on the web canvas */
  --segmented-bg: oklch(0.7907 0.0074 286.229 / 0.22); /* recessed translucent well */
  --segmented-active-bg: oklch(1 0 0 / 0.85); /* raised glass segment */
  /* Subtle canvas gradient: whisper of top-light + cool floor so frosted surfaces read as glass, not flat fill. Low-alpha on purpose. */
  --canvas-gradient: linear-gradient(
    170deg,
    oklch(1 0 0 / 0.75) 0%,
    oklch(0.96 0.006 255 / 0.2) 48%,
    oklch(0.9 0.014 262 / 0.4) 100%
  );
  /* Float gap: wide enough that soft drop shadow renders on all sides (native p-2/8px was too tight). */
  --sidebar-float-gap: 0.875rem;
  /* DS menu material (Figma 2004:25200/25203) doesn't translate to CSS: Figma's stacked-fill blend
   * modes + inner-shadow spread math produce different results in background-blend-mode/box-shadow.
   * We reproduce the DS's VISUAL RESULT instead: one translucent grey fill + white top gloss + hairline + soft drop. */
  --popup-fill: rgba(217, 217, 217, 0.55);
  /* Shared glass "look" (popover, sidebar, …): white top gloss + hairline edge. Drop/lift added
   * per-surface (popover = big soft ambient; edge-pinned sidebar = contained, avoids clipping). */
  --surface-gloss: rgba(255, 255, 255, 0.6);
  --surface-hairline: rgba(0, 0, 0, 0.1);
  --menu-shadow:
    inset 0 1px 0 0 var(--surface-gloss),
    inset 0 0 0 0.5px var(--surface-hairline),
    0 8px 48px 0 rgba(0, 0, 0, 0.2),
    0 1px 3px 0 rgba(0, 0, 0, 0.12);
  --apple-liquid-refraction: 0.85;
  --apple-liquid-modal-refraction: 0.92;
  --apple-liquid-edge-band: 32;
  --apple-liquid-edge-ratio: 0.36;
  --apple-liquid-modal-edge-ratio: 0.25;
  --apple-liquid-edge-darkening: 0.025;
  --apple-liquid-specular: 0.11;
  --apple-liquid-fresnel: 0.35;
  --apple-liquid-edge-highlight: 0.16;
  --apple-liquid-center-diffusion: 0.38;
  --apple-liquid-edge-diffusion: 0.08;
  --apple-liquid-modal-center-diffusion: 0.82;
  --apple-liquid-modal-edge-diffusion: 0.32;
  --apple-liquid-fill: 0.32;
  --apple-liquid-modal-fill: 0.6;
  --apple-liquid-shadow:
    0 12px 28px -12px oklch(0.2244 0.0257 263.845 / 0.28),
    0 2px 7px -3px oklch(0.2244 0.0257 263.845 / 0.16);
  --apple-liquid-modal-shadow:
    0 24px 48px -20px oklch(0.2244 0.0257 263.845 / 0.32),
    0 4px 12px -5px oklch(0.2244 0.0257 263.845 / 0.18);
  /* macOS menu selection blue (DS node 2004:25249): solid pill + white text, not translucent tint. Same both modes. */
  --menu-selection: oklch(0.5641 0.2301 259.998);
}

:where(.dark) [data-skin="modern-apple"],
.dark[data-skin="modern-apple"] {
  --hairline: oklch(1 0 0 / 0.1);
  --glass-fill: oklch(1 0 0 / 0.12);
  --glass-fill-hover: oklch(1 0 0 / 0.18);
  --glass-fill-active: oklch(1 0 0 / 0.08);
  /* Dark controls over glass (DS node 2004:21141): subtle fill + whisper edge, NOT heavy rim+gloss.
   * Old white 0.28 rim/0.30 gloss read as "big border" on dark; dropped hard. */
  --glass-rim: oklch(1 0 0 / 0.09);
  --glass-gloss: oklch(1 0 0 / 0.07);
  --segmented-bg: oklch(0.559 0.0147 285.916 / 0.3);
  --segmented-active-bg: oklch(1 0 0 / 0.16);
  /* Canvas uses the DS Window Background with whisper top-light; the old high-contrast gradient was too uneven. */
  --canvas-gradient: linear-gradient(180deg, oklch(0.25 0 0) 0%, oklch(0.235 0 0) 55%, oklch(0.223 0 0) 100%);
  /* Dark menu material (DS node 2004:25203): graphite rgba(64,64,64,.8) fill + light inner ring +
   * thin edge rim + soft drop. DS's background-blend-mode:luminosity is a no-op in CSS (see light
   * block) so tone is baked into fill alpha instead. */
  --popup-fill: rgba(64, 64, 64, 0.8);
  --surface-gloss: rgba(255, 255, 255, 0.12);
  --surface-hairline: rgba(255, 255, 255, 0.2);
  --menu-shadow:
    inset 0 0 0 0.5px var(--surface-hairline),
    1.25px 0 0 -0.75px rgba(219, 219, 219, 0.55),
    -1.25px 0 0 -0.75px rgba(219, 219, 219, 0.55),
    0 0 0 0.5px rgba(219, 219, 219, 0.5),
    0 8px 48px 0 rgba(0, 0, 0, 0.45);
  --apple-liquid-shadow:
    0 14px 32px -12px oklch(0 0 0 / 0.56),
    0 2px 8px -3px oklch(0 0 0 / 0.42);
  --apple-liquid-modal-shadow:
    0 28px 56px -20px oklch(0 0 0 / 0.62),
    0 5px 14px -5px oklch(0 0 0 / 0.46);
  --apple-liquid-fill: 0.5;
  --apple-liquid-modal-fill: 0.76;
  --menu-selection: oklch(0.5641 0.2301 259.998);
}

/* DS popup material for every floating list/panel: one translucent grey fill (--popup-fill) +
 * --menu-shadow (inner edge-darkening/ring + outer drop/hairline). The unlayered skin rule beats
 * layered base materials while geometry stays in the shared popover classes. */
[data-skin="modern-apple"]
  :is([data-control-ui][data-slot][data-surface="floating"], [data-control-ui][data-slot][data-surface="modal"]) {
  background: var(--popup-fill);
  -webkit-backdrop-filter: none;
  backdrop-filter: none;
  box-shadow: var(--menu-shadow);
  border: 0;
}

/* The WebGL frame owns transmission and edge light after readiness; only external elevation remains in CSS. */
[data-skin="modern-apple"] [data-control-ui][data-apple-liquid-glass-ready="true"] {
  background: transparent;
  -webkit-backdrop-filter: none;
  backdrop-filter: none;
  border: 0;
  box-shadow: var(--apple-liquid-shadow);
}

[data-skin="modern-apple"] [data-control-ui][data-apple-liquid-glass-profile="modal"][data-apple-liquid-glass-ready="true"] {
  box-shadow: var(--apple-liquid-modal-shadow);
}

/* apple-glass: shared translucent material for ad-hoc panels wanting the same read as popover
 * surfaces (--popover-opacity/--backdrop-blur-popover); adds white top-edge gloss via inset ring. */
[data-skin="modern-apple"] .apple-glass {
  background-color: oklch(from var(--popover) l c h / var(--popover-opacity));
  -webkit-backdrop-filter: blur(var(--backdrop-blur-popover)) saturate(1.8);
  backdrop-filter: blur(var(--backdrop-blur-popover)) saturate(1.8);
  box-shadow: inset 0 1px 0 0 var(--glass-gloss);
}

/* Floating-sidebar glass: uses NATIVE shadcn `floating` layout (ControlUiSkin.sidebarLayout), which
 * already draws gap/padding/rounding/border/shadow. Here: (1) re-materialise as Liquid Glass, (2)
 * widen float gap so drop shadow isn't clipped (native p-2/8px < shadow blur). Not an overflow bug. */
[data-skin="modern-apple"] [data-control-ui="sidebar"][data-slot="root"][data-variant="floating"] [data-control-ui="sidebar"][data-slot="container"] {
  padding: var(--sidebar-float-gap);
  overflow: visible; /* the main sidebar is not a resizable clip panel — never crop its own shadow */
}

/* Floating sidebar uses lighter --popover-based glass, NOT grey --popup-fill (distinct from menu
 * surface, per user pref). Shares surface gloss+0.5px hairline; CONTAINED drop (popover's big
 * ambient would clip at this edge-pinned panel's float gap). border:0 — hairline IS the edge. */
[data-skin="modern-apple"] [data-control-ui="sidebar"][data-slot="root"][data-variant="floating"] [data-control-ui="sidebar"][data-slot="inner"] {
  corner-shape: var(--corner-shape-panel, var(--corner-shape, round));
  border: 0;
  background-color: oklch(from var(--popover) l c h / var(--popover-opacity));
  -webkit-backdrop-filter: blur(var(--backdrop-blur-popover)) saturate(1.8);
  backdrop-filter: blur(var(--backdrop-blur-popover)) saturate(1.8);
  box-shadow:
    inset 0 1px 0 0 var(--surface-gloss),
    inset 0 0 0 0.5px var(--surface-hairline),
    0 3px 12px -1px rgba(0, 0, 0, 0.14),
    0 1px 4px rgba(0, 0, 0, 0.08);
}

/* Collapsed icon rail: reserve wider float gap on both gap+container so ~3rem icon column isn't
 * eaten by padding (native floating only budgets 8px). data-collapsible="icon" only while collapsed. */
[data-skin="modern-apple"] [data-control-ui="sidebar"][data-slot="root"][data-variant="floating"][data-collapsible="icon"] [data-control-ui="sidebar"][data-slot="gap"],
[data-skin="modern-apple"] [data-control-ui="sidebar"][data-slot="root"][data-variant="floating"][data-collapsible="icon"] [data-control-ui="sidebar"][data-slot="container"] {
  width: calc(var(--sidebar-width-icon) + var(--sidebar-float-gap) * 2 + 2px);
}

/* Canvas gets glass gradient; background-attachment:fixed pins it so wrapper+inset share one seamless wash. */
[data-skin="modern-apple"] :is([data-control-ui="sidebar"][data-slot="wrapper"], [data-control-ui="sidebar"][data-slot="inset"]) {
  background-image: var(--canvas-gradient);
  background-attachment: fixed;
}

/* Content stays flat: config slot already strips frame border/radius/bg/shadow; this guards against residual box-shadow. */
[data-skin="modern-apple"] :is([data-control-ui="sidebar"][data-slot="inset"], [data-control-ui="sidebar-layout"][data-slot="content"]) {
  box-shadow: none;
}

/* scroll fades + streaming sweep come from library effects.css (token-driven, recolor for free). */

@layer components {
  /* Apple segmented control: recessed well + raised glass segment. Pure re-values of library's
   * component-local knobs; geometry/states/line variant stay baseline's. */
  [data-skin="modern-apple"] :where([data-control-ui="tabs"][data-slot="list"]) {
    --tabs-trigger-radius: 0.5625rem; /* 9px segment corner */
    --tabs-list-padding: 0.125rem; /* the tight 2px well inset */
    --tabs-list-gap: 0.125rem;
    --tabs-list-bg: var(--segmented-bg);
    --tabs-list-backdrop-filter: blur(var(--backdrop-blur-glass));
    --tabs-indicator-bg: var(--segmented-active-bg);
    --tabs-indicator-shadow:
      inset 0 1px 0 0 var(--glass-gloss),
      0 1px 3px oklch(from var(--shadow-color) l c h / 0.18),
      0 0 0 0.5px oklch(from var(--shadow-color) l c h / 0.04);
    --tabs-indicator-ease: var(--ease-emphasized);
    --tabs-trigger-font-size: var(--text-body);
    --tabs-trigger-focus-shadow: 0 0 0 3px var(--ring);
    --tabs-line-border-color: var(--hairline);
    --tabs-line-indicator-bg: var(--primary);
  }
}

/*
 * Modern Apple owns the complete token contract plus skin.css glass materials and skin.config slots —
 * a Liquid Glass reading of iOS 26/macOS Tahoe. Shared @theme bindings remain in Control UI core.
 */

[data-skin="modern-apple"] {
  /* typography — the SF stack; small chrome runs a rung larger via the type re-values below */
  --font-sans: -apple-system, BlinkMacSystemFont, "SF Pro Text", "SF Pro Display", "Helvetica Neue", Helvetica, Arial, sans-serif;
  --font-mono: "SF Mono", ui-monospace, SFMono-Regular, Menlo, monospace;

  /* type scale — small chrome bumped one rung (11/12/13px micro/meta/label); body stays 14px */
  --text-micro: 0.6875rem; /* 11px */
  --text-meta: 0.75rem; /* 12px */
  --text-label: 0.8125rem; /* 13px */

  /* shadcn base names, authored in oklch; derived tokens use relative color syntax to track author format. */
  --background: oklch(1 0 0);
  --foreground: oklch(0.2178 0 89.876); /* #1A1A1A — DS Labels/Vibrant Primary */
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.2178 0 89.876);
  --popover: oklch(0.995 0 0); /* near-white glass base, frosted by --popover-opacity below */
  --popover-foreground: oklch(0.2178 0 89.876);
  --primary: oklch(0.556 0.2018 254.088); /* iOS system-blue hue, darkened for accessible action text */
  --primary-foreground: oklch(1 0 0);
  --primary-text: oklch(from var(--primary) 0.48 c h);
  --muted: oklch(0.9673 0.0024 286.354); /* #F5F5F7 parchment */
  --muted-foreground: oklch(0.5521 0 89.876); /* #727272 — DS Labels/Vibrant Secondary */
  --secondary: oklch(0.9364 0.0027 286.347); /* #E9E9EB — assistant bubble gray */
  --secondary-foreground: oklch(0.2178 0 89.876);
  --accent: oklch(0.9673 0.0024 286.354);
  --accent-foreground: oklch(0.2178 0 89.876);
  --destructive: oklch(0.583 0.2328 25.739); /* iOS system-red hue, darkened for accessible action text */
  --destructive-foreground: oklch(1 0 0);
  --destructive-text: oklch(from var(--destructive) 0.48 c h);

  /* "Ring white" contract: resting + focus ring both white (glass rim / soft halo), not the usual blue outline. */
  --ring-opacity: 0.55;
  --border: oklch(from oklch(1 0 0) l c h / var(--ring-opacity)); /* white hairline rim */
  --input: oklch(1 0 0 / 0.45); /* transparent-glass field border, white */
  --ring: oklch(1 0 0 / 0.9); /* white focus halo */

  /* page canvas — the light neutral desktop the glass floats on */
  --canvas: oklch(0.9466 0 0); /* #ECECEC */

  /* Glass pair frosts popover/dropdown/select/context-menu/dialog together (all read bg-popover).
     Calibrated between DS Frost L/M=16 and apple.com blur(20px) for refined-not-heavy reading. */
  --popover-opacity: 0.62;
  --backdrop-blur-popover: 18px; /* DS Liquid Glass/Frost — Large = 16; +2 for the web canvas */

  /* The liquid surface owns optical diffusion; the modal backdrop only dims. */
  --overlay-opacity: 0.2;
  --backdrop-blur-overlay: 0px;

  --scroll-fade-size: 2rem;

  /* elevation — Apple shadows are soft, large, and low-contrast */
  --shadow-color: oklch(0.2244 0.0257 263.845);
  --shadow-size: 1;
  --shadow-opacity: 0.85;
  --shadow-y: 1;
  --shadow-control-multiplier: 1;
  --shadow-panel-multiplier: 2;
  --shadow-popover-multiplier: 4;
  --shadow-modal-multiplier: 5;
  --shadow-ambient-multiplier: 8;

  /* THE one radius knob. Continuous, generous Apple corners: ~14px surfaces, ~11px controls. */
  --radius: 0.875rem;
  --radius-control: calc(var(--radius) * 0.78); /* ~11px push-button / field corner */
  /* Radius divergence from Refined: TIGHTER ratios (1.9x field/1.7x panel/2x scene) so continuous corners don't balloon. */
  --radius-field: calc(var(--radius) * 1.9); /* user bubble, composer shell */
  --radius-panel: calc(var(--radius) * 1.7); /* code / markdown surfaces */
  --radius-scene: calc(var(--radius) * 2); /* scene frame, large media */

  /* Apple's continuous (superellipse) corners since iOS 7; `squircle` is the CSS corner-shape for it. */
  --corner-shape: squircle;
  --corner-shape-control: var(--corner-shape);
  --corner-shape-popover: var(--corner-shape);
  --corner-shape-panel: var(--corner-shape);

  /* floating-list geometry (menu / select / context-menu). Rows inset 5px, concentric container. */
  --popover-padding: 0.3125rem; /* 5px gap between container edge and rows */
  --radius-popup-item: 0.5rem; /* 8px menu-row corner */
  /* sub-pixel guard for a rounded child inside an overflow-clipped rounded container */
  --nest-safe: 1px;
  /* corner-fit ratio = 2 + √2 (see the Refined skin for the derivation) */
  --nest-corner-ratio: 3.41421356;
  --radius-popup-item-fit: min(var(--radius-popup-item), calc(var(--control-h-xs) / 2));
  --radius-popover: calc(var(--radius-popup-item-fit) + clamp(0px, var(--radius-popup-item-fit) * 1000, var(--popover-padding)));

  /* content density for the rounded surfaces (bubble / composer field) */
  --padding-x: 1rem;
  --padding-y: 0.5rem;

  /* control size scale — ONE base height; xs/sm/md/lg are COMPUTED from it. ~34px regular controls. */
  --control-h: 2.125rem;
  --control-h-xs: round(var(--control-h) * 0.78, 1px);
  --control-h-sm: round(var(--control-h) * 0.89, 1px);
  --control-h-md: var(--control-h);
  --control-h-lg: round(var(--control-h) * 1.11, 1px);

  /* Apple system springs overshoot+settle elastically; CSS has no native spring, so --ease-emphasized
     is a `linear()` spring (~8% overshoot) driving popups/tabs-indicator/select-chevron/panel-enter.
     --ease-standard stays smooth easeOut for color/text (bounce reads as jitter); tempo runs longer. */
  --ease-standard: cubic-bezier(0.33, 1, 0.68, 1);
  --ease-emphasized: linear(
    0, 0.006, 0.025 3.1%, 0.101 7.3%, 0.276 12.5%, 0.578 19.8%, 0.73 24%, 0.853, 0.949 31.9%, 1.008,
    1.062 39.5%, 1.079, 1.085, 1.08 46.9%, 1.055 52.2%, 1.014 60.4%, 0.995 66.6%, 0.985 72.9%,
    0.987 80.2%, 0.997 91.7%, 1
  );
  --duration-fast: 200ms;
  --duration-base: 340ms;
  --duration-slow: 520ms;

  --popup-item-foreground: var(--foreground);
  --popup-item-icon-foreground: currentColor;
  --popup-item-highlight-background: oklch(from var(--foreground) l c h / 0.06);
  --badge-neutral: oklch(from var(--foreground) l c h / 0.08);
  --badge-neutral-foreground: var(--foreground);
  --badge-neutral-border: oklch(from var(--foreground) l c h / 0.1);
  --badge-neutral-hover: oklch(from var(--foreground) l c h / 0.12);
  --badge-slate: oklch(from var(--color-slate-500) l c h / 0.14);
